module RefModule (
  input clk,
  input reset_n,
  input up,
  input down,
  output reg [2:0] count
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
    if (!reset_n)
        count <= 3'b000;
    else if (up && !down)
        count <= count + 1;
    else if (!up && down)
        count <= count - 1;
end

endmodule
